// === Settle GL Reconciliation — Reconciliation Report ===
const TOL = 0.10;
const WINDOW_DAYS = 3;

const settle = $('Extract Settle Payments').all().map(i => i.json);
const bank   = $('Extract Bank').all().map(i => i.json);

const parseDate = s => new Date(s);
const daysBetween = (a, b) => Math.abs((a - b) / (1000 * 60 * 60 * 24));

const bankUsed = new Set();
const out = [];

for (const sp of settle) {
  const spDate = parseDate(sp.payment_date);
  const spAmt = parseFloat(sp.amount);
  let found = null;
  for (let i = 0; i < bank.length; i++) {
    if (bankUsed.has(i)) continue;
    const b = bank[i];
    if (!String(b.description).includes('SETTLE PAYMENT')) continue;
    const bAmt = -parseFloat(b.amount);
    const bDate = parseDate(b.date);
    if (Math.abs(bAmt - spAmt) <= TOL && daysBetween(bDate, spDate) <= WINDOW_DAYS) { found = i; break; }
    if (daysBetween(bDate, spDate) <= 1 && Math.abs(bAmt - spAmt) <= 1.0) { found = i; break; }
  }
  if (found !== null) {
    bankUsed.add(found);
    const b = bank[found];
    const diff = Math.round((-parseFloat(b.amount) - spAmt) * 100) / 100;
    if (Math.abs(diff) > TOL) {
      out.push({ json: { category: 'settle_payment', status: 'AMOUNT_DIFF',
        detail: `${sp.payment_id} settle $${spAmt.toFixed(2)} vs bank $${(-parseFloat(b.amount)).toFixed(2)}`,
        amount: diff } });
    } else {
      out.push({ json: { category: 'settle_payment', status: 'MATCHED', detail: sp.payment_id, amount: spAmt } });
    }
  } else {
    out.push({ json: { category: 'settle_payment', status: 'NO_BANK', detail: sp.payment_id, amount: spAmt } });
  }
}

for (let i = 0; i < bank.length; i++) {
  if (bankUsed.has(i)) continue;
  const b = bank[i];
  const amt = parseFloat(b.amount);
  if (amt >= 0) continue;
  const d = String(b.description);
  if (d.includes('SETTLE') || d.includes('SHOPIFY') || d.includes('AMAZON')) continue;
  out.push({ json: { category: 'bank_outflow', status: 'UNMATCHED', detail: `${b.date} ${b.description}`, amount: amt } });
}

return out;

// === Settle GL Reconciliation — Journal Entries ===
const settle  = $('Extract Settle Payments').all().map(i => i.json);
const loan    = $('Extract Settle Loan').all().map(i => i.json);
const bank    = $('Extract Bank').all().map(i => i.json);
const shopify = $('Extract Shopify').all().map(i => i.json);
const amazon  = $('Extract Amazon').all().map(i => i.json);

const PERIOD = '2026-04';
const sum = (arr, key) => arr.reduce((s, r) => s + parseFloat(r[key] || 0), 0);
const round = v => Math.round(v * 100) / 100;

const totalSettle    = sum(settle, 'amount');
const totalInterest  = sum(loan, 'interest_paid');
const totalPrincipal = sum(loan, 'principal_paid');
const shopifyCOGS    = sum(shopify, 'cogs');
const amazonFees     = sum(amazon, 'fees');
const amazonCOGS     = sum(amazon, 'cogs');

const shopifyDeposits = bank.filter(b => String(b.description).includes('SHOPIFY'))
                            .reduce((s, b) => s + parseFloat(b.amount), 0);
const amazonDeposits  = bank.filter(b => String(b.description).includes('AMAZON'))
                            .reduce((s, b) => s + parseFloat(b.amount), 0);

const je = [
  { account: 'Inventory / COGS Capitalized', debit: round(totalSettle), credit: 0,
    memo: `Settle-funded vendor payments (${settle.length} invoices, ${PERIOD})` },
  { account: 'Settle Loan Payable',          debit: 0, credit: round(totalSettle),
    memo: `Settle financing drawn (${PERIOD})` },
  { account: 'Interest Expense - Settle',    debit: round(totalInterest), credit: 0,
    memo: 'Monthly interest accrued' },
  { account: 'Settle Loan Payable',          debit: round(totalPrincipal), credit: 0,
    memo: 'Monthly principal repayment' },
  { account: 'Bank - Operating',             debit: 0, credit: round(totalInterest + totalPrincipal),
    memo: 'Settle sweep (interest + principal)' },
  { account: 'Bank - Operating',             debit: round(shopifyDeposits), credit: 0,
    memo: `Shopify payouts received (${PERIOD})` },
  { account: 'Revenue - Shopify',            debit: 0, credit: round(shopifyDeposits),
    memo: 'Net Shopify payout' },
  { account: 'Bank - Operating',             debit: round(amazonDeposits), credit: 0,
    memo: 'Amazon FBA settlements received' },
  { account: 'Amazon Fees',                  debit: round(amazonFees), credit: 0,
    memo: 'Amazon FBA fees absorbed' },
  { account: 'Revenue - Amazon',             debit: 0, credit: round(amazonDeposits + amazonFees),
    memo: 'Gross Amazon revenue' },
  { account: 'COGS',                         debit: round(shopifyCOGS + amazonCOGS), credit: 0,
    memo: 'Cost of goods sold across channels' },
  { account: 'Inventory',                    debit: 0, credit: round(shopifyCOGS + amazonCOGS),
    memo: 'Inventory consumed' },
];

const td = round(je.reduce((s, j) => s + j.debit, 0));
const tc = round(je.reduce((s, j) => s + j.credit, 0));
je.push({ account: '--- BALANCE CHECK ---', debit: td, credit: tc,
          memo: Math.abs(td - tc) < 0.05 ? 'BALANCED' : `OUT OF BALANCE by $${(td - tc).toFixed(2)}` });

return je.map(j => ({ json: j }));
